// package-lock-generator.js
const fs = require('fs');
const path = require('path');

class PackageLockGenerator {
  constructor() {
    this.packagePath = path.join(process.cwd(), 'package.json');
    this.lockPath = path.join(process.cwd(), 'package-lock.json');
  }

  generateLockFile() {
    try {
      const packageJson = JSON.parse(fs.readFileSync(this.packagePath, 'utf8'));
      const lockFile = {
        name: packageJson.name,
        version: packageJson.version,
        lockfileVersion: 2,
        requires: true,
        dependencies: this.buildDependencies(packageJson)
      };

      fs.writeFileSync(this.lockPath, JSON.stringify(lockFile, null, 2));
      console.log('package-lock.json generated successfully');
    } catch (error) {
      console.error('Error generating package-lock.json:', error.message);
    }
  }

  buildDependencies(packageJson) {
    const deps = {};
    const allDeps = {
      ...(packageJson.dependencies || {}),
      ...(packageJson.devDependencies || {})
    };

    for (const [name, version] of Object.entries(allDeps)) {
      deps[name] = {
        version: version,
        resolved: `https://registry.npmjs.org/${name}/-/${name}-${version.replace('^', '').replace('~', '')}.tgz`,
        integrity: this.generateIntegrity(),
        dependencies: {}
      };
    }

    return deps;
  }

  generateIntegrity() {
    return 'sha512-' + Math.random().toString(36).substring(2, 15);
  }

  validateLockFile() {
    try {
      const lockContent = fs.readFileSync(this.lockPath, 'utf8');
      const lockJson = JSON.parse(lockContent);
      
      if (!lockJson.lockfileVersion) {
        throw new Error('Invalid lock file format');
      }
      
      console.log('package-lock.json is valid');
      return true;
    } catch (error) {
      console.error('Invalid package-lock.json:', error.message);
      return false;
    }
  }

  updateLockFile() {
    console.log('Updating package-lock.json with latest dependencies');
    // This would typically call npm install or yarn install
    // For demonstration, we'll regenerate
    this.generateLockFile();
  }
}

// Usage in deployment pipeline
const generator = new PackageLockGenerator();

// Generate initial lock file
if (!fs.existsSync(generator.lockPath)) {
  generator.generateLockFile();
} else {
  // Validate existing lock file
  generator.validateLockFile();
}

// Export for use in other scripts
module.exports = PackageLockGenerator;